// MARK: - Universal Link Handler

class UniversalLinkHandler {
    static let shared = UniversalLinkHandler()
    
    private let validHost = "myapp.com"
    private let promoPath = "/promo"
    
    private init() {}
    
    struct PromoLinkData {
        let code: String
        let discount: Int
        let rawURL: URL
    }
    
    func handleUniversalLink(_ url: URL) -> PromoLinkData? {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            print("[UniversalLinkHandler] Failed to parse URL components from: \(url)")
            return nil
        }
        
        // Validate host
        guard components.host == validHost else {
            print("[UniversalLinkHandler] Invalid host: \(components.host ?? "nil")")
            return nil
        }
        
        // Validate path
        guard components.path == promoPath else {
            print("[UniversalLinkHandler] Invalid path: \(components.path)")
            return nil
        }
        
        // Extract query parameters
        guard let queryItems = components.queryItems else {
            print("[UniversalLinkHandler] No query parameters found")
            return nil
        }
        
        let code = queryItems.first(where: { $0.name == "code" })?.value
        let discountString = queryItems.first(where: { $0.name == "discount" })?.value
        
        guard let promoCode = code, !promoCode.isEmpty else {
            print("[UniversalLinkHandler] Missing or empty promo code")
            return nil
        }
        
        guard let discountStr = discountString, let discount = Int(discountStr) else {
            print("[UniversalLinkHandler] Missing or invalid discount value")
            return nil
        }
        
        print("[UniversalLinkHandler] Extracted promo - Code: \(promoCode), Discount: \(discount)%")
        
        return PromoLinkData(code: promoCode, discount: discount, rawURL: url)
    }
}

